html: <!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Scroll Progress Bar</title>
    <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/tailwindcss/2.2.19/tailwind.css">
</head>
<body>
    <div class="w-full h-4 bg-gray-300 fixed top-0 left-0 z-10">
        <div class="bg-orange-500 h-4 w-0 transition-width duration-500 ease-in-out opacity-100">
            <div class="absolute top-0 left-0 w-full h-full bg-orange-500" style="background-image: linear-gradient(to right, rgba(255, 140, 0, 0), rgba(255, 140, 0, 1));"></div>
        </div>
    </div>
    <script>
        const progressBar = document.querySelector('.progress-bar .bg-orange-500');
        const progressBarWidth = document.querySelector('.progress-bar .bg-orange-500').offsetWidth;
        const scrollPosition = document.body.scrollTop;
        const maxHeight = document.body.scrollHeight - window.innerHeight;
        const progress = scrollPosition / maxHeight;
        progressBar.style.width = `${progress * 100}%`;
        window.addEventListener("scroll", () => {
            progressBar.style.width = `${(document.body.scrollTop / maxHeight) * 100}%`;
        });
    </script>
</body>
</html>
